function solve(n: number, edges: number[][]): number {
    // Build adjacency list
    const adj: Map<number, { to: number; start: number; end: number }[]> = new Map();
    for (const [u, v, s, e] of edges) {
        if (!adj.has(u)) {
            adj.set(u, []);
        }
        adj.get(u)!.push({ to: v, start: s, end: e });
    }

    // Dijkstra's algorithm with priority queue
    const pq: [number, number][] = [[0, 0]]; // [time, node]
    const dist: Map<number, number> = new Map();
    dist.set(0, 0);

    while (pq.length > 0) {
        // Sort by time
        pq.sort((a, b) => a[0] - b[0]);
        const [time, node] = pq.shift()!;

        // If we have already found a better time for this node, skip
        if (dist.get(node) !== undefined && dist.get(node) < time) {
            continue;
        }

        // If we reached the destination
        if (node === n - 1) {
            return time;
        }

        // Try to move along each outgoing edge
        if (adj.has(node)) {
            for (const { to, start, end } of adj.get(node)!) {
                // Check if the edge is available at the current time
                if (start <= time && time <= end) {
                    // We can take this edge, move to the next node at time + 1
                    const newTime = time + 1;
                    if (!dist.has(to) || newTime < dist.get(to)!) {
                        dist.set(to, newTime);
                        pq.push([newTime, to]);
                    }
                }
            }
        }

        // Also consider staying at the current node (time + 1)
        const newTime = time + 1;
        if (!dist.has(node) || newTime < dist.get(node)!) {
            dist.set(node, newTime);
            pq.push([newTime, node]);
        }
    }

    // If we couldn't reach the destination
    return -1;
}

